insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (256631, 271095, 9, 'msdevlab', 'Pirates of the Caribbean 2 and Raiders of the Lost Ark both build adventure around dangerous treasure hunts, witty heroes, and set pieces that keep the story moving.', null);  -- 256631 Pirates of the Caribbean 2 2006 | 271095 Raiders of the Lost Ark 1981
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (256631, 159172, 9, 'msdevlab', 'Pirates of the Caribbean 2 and The Last Crusade both combine humor, mythology, and fast adventure, with the quest itself revealing more about the heroes'' relationships.', null);  -- 256631 Pirates of the Caribbean 2 2006 | 159172 Indiana Jones and the Last Crusade 1989
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (313478, 194502, 9, 'msdevlab', 'The Empire Strikes Back and The Two Towers are both darker middle chapters where the heroes are separated, tested, and forced to keep hope alive before the final battle.', null);  -- 313478 Star Wars: Episode V - The Empire Strikes Back 1980 | 194502 Lord of the Rings: The Two Towers, The 2002
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (313477, 194495, 9, 'msdevlab', 'Revenge of the Sith and Return of the King both feel like epic conclusions, using large battles and emotional good-versus-evil choices to give the saga real weight.', null);  -- 313477 Star Wars: Episode III - Revenge of the Sith 2005 | 194495 Lord of the Rings: Return of the King, The (2003/II) 2003
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (313479, 194495, 9, 'msdevlab', 'Return of the Jedi and Return of the King both close beloved trilogies with rescue missions, final confrontations, and a strong sense of emotional resolution.', null);  -- 313479 Star Wars: Episode VI - Return of the Jedi 1983 | 194495 Lord of the Rings: Return of the King, The (2003/II) 2003
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (300229, 210739, 9, 'msdevlab', 'Shrek and Men in Black both mix fantasy or sci-fi worlds with fast comedy, using a strange duo dynamic to make the adventure feel fun rather than childish.', null);  -- 300229 Shrek 2001 | 210739 Men in Black 1997
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (300230, 210739, 9, 'msdevlab', 'Shrek 2 and Men in Black both turn bizarre creatures and hidden worlds into sharp comedy, while still giving the main characters clear emotional loyalty.', null);  -- 300230 Shrek 2 2004 | 210739 Men in Black 1997
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (30959, 214755, 9, 'msdevlab', 'Batman Begins and Minority Report both use sleek thriller pacing, moral pressure, and a hero hunted by powerful systems to make the action feel intelligent.', null);  -- 30959 Batman Begins 2005 | 214755 Minority Report 2002
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (162380, 215880, 9, 'msdevlab', 'Iron Man and Mission: Impossible III both center on charismatic heroes facing personal danger, advanced technology, and action that depends on quick thinking rather than strength alone.', null);  -- 162380 Iron Man 2005 | 215880 Mission: Impossible III 2006
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (158999, 335835, 9, 'msdevlab', 'Independence Day and Top Gun both deliver patriotic action built around confident heroes, teamwork, and big crowd-pleasing moments that still feel emotionally clear.', null);  -- 158999 Independence Day 1996 | 335835 Top Gun 1986
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (359297, 247579, 9, 'msdevlab', 'War of the Worlds and Panic Room both create suspense from a family trapped under threat, making survival feel personal, immediate, and easy to follow.', null);  -- 359297 War of the Worlds 2005 | 247579 Panic Room 2002
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (185628, 340652, 9, 'msdevlab', 'The Last Samurai and Troy both explore warrior honor in historical settings, focusing on men caught between loyalty, identity, and the cost of battle.', null);  -- 185628 Last Samurai, The 2003 | 340652 Troy 2004
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (333856, 151616, 9, 'msdevlab', 'Titanic and How to Lose a Guy in 10 Days are very different in scale, but both depend on strong romantic chemistry and a relationship tested by social pressure and deception.', null);  -- 333856 Titanic 1997 | 151616 How to Lose a Guy in 10 Days 2003
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (263360, 644, 9, 'msdevlab', 'Pretty Woman and 10 Things I Hate About You both turn a familiar romance setup into something memorable through sharp chemistry, strong female leads, and emotional payoff.', null);  -- 263360 Pretty Woman 1990 | 644 10 Things I Hate About You 1999
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (238073, 56871, 9, 'msdevlab', 'Ocean''s Twelve and Catch Me If You Can both enjoy clever deception, stylish escapes, and the pleasure of watching charming characters stay one step ahead.', null);  -- 238073 Ocean's Twelve 2004 | 56871 Catch Me If You Can 2002
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (297838, 129185, 9, 'msdevlab', 'The Shawshank Redemption and Gladiator both turn injustice into a powerful personal journey, rewarding patience, loyalty, and hope through very satisfying endings.', null);  -- 297838 Shawshank Redemption, The 1994 | 129185 Gladiator 2000
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (328272, 333856, 9, 'msdevlab', 'The Terminal and Titanic both follow kind-hearted characters trapped by circumstances beyond their control, making the emotional connection more important than the setting itself.', null);  -- 328272 Terminal, The 2004 | 333856 Titanic 1997
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (142491, 311037, 9, 'msdevlab', 'Hellboy and Spider-Man both follow outsiders with unusual powers who struggle with acceptance while still choosing to protect people who do not fully understand them.', null);  -- 142491 Hellboy 2004 | 311037 Spider-Man 2002
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (142492, 311038, 9, 'msdevlab', 'Hellboy 2 and Spider-Man 2 both improve superhero storytelling by giving the hero stronger emotional conflict alongside creative villains and memorable action sequences.', null);  -- 142492 Hellboy 2 2006 | 311038 Spider-Man 2 2004
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (370017, 335835, 9, 'msdevlab', 'XXX and Top Gun both focus on fearless, competitive men whose confidence and physical skill drive fast, high-risk action in a very entertaining way.', null);  -- 370017 XXX 2002 | 335835 Top Gun 1986
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (86263, 215880, 9, 'msdevlab', 'Die Another Day and Mission: Impossible III both deliver modern spy action with gadgets, international threats, and a lead character pushed through stylish high-pressure missions.', null);  -- 86263 Die Another Day 2002 | 215880 Mission: Impossible III 2006
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (86263, 92573, 2, 'msdevlab', 'The James Bond connection is clear, but Dr. No feels like an early, stripped-down spy story; it lacks the modern gadgets, speed, and spectacle that make Die Another Day entertaining.', null);  -- 86263 Die Another Day 2002 | 92573 Dr. No 1962
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (86263, 120574, 2, 'msdevlab', 'A Bond fan may understand the pairing, yet From Russia with Love is built around slow Cold War espionage and train suspense rather than Die Another Day''s flashy action style.', null);  -- 86263 Die Another Day 2002 | 120574 From Russia with Love 1963
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (86263, 85871, 2, 'msdevlab', 'Diamonds Are Forever uses campy Las Vegas humor and an older Connery-era rhythm, so it would feel like the wrong follow-up to Die Another Day''s sleek, gadget-heavy adventure.', null);  -- 86263 Die Another Day 2002 | 85871 Diamonds Are Forever 1971
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (86263, 192514, 2, 'msdevlab', 'Live and Let Die shares the Bond formula, but its dated tone and unusual voodoo storyline do not fit the fast, modern spy-adventure feeling of Die Another Day.', null);  -- 86263 Die Another Day 2002 | 192514 Live and Let Die 1973
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (86263, 372233, 2, 'msdevlab', 'You Only Live Twice has a large villain plan, yet its 1960s pacing and outdated stereotypes make it a weak match for someone drawn to Die Another Day''s quick modern action.', null);  -- 86263 Die Another Day 2002 | 372233 You Only Live Twice 1967
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (86263, 332065, 2, 'msdevlab', 'Thunderball includes exotic Bond danger, but the long underwater scenes make it much slower than the energetic, gadget-driven pace that Die Another Day fans would expect.', null);  -- 86263 Die Another Day 2002 | 332065 Thunderball 1965
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (335336, 92573, 2, 'msdevlab', 'Dr. No is historically important for Bond, yet it does not deliver the media-villain plot, fast chases, or modern action rhythm that make Tomorrow Never Dies appealing.', null);  -- 335336 Tomorrow Never Dies 1997 | 92573 Dr. No 1962
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (335336, 85871, 2, 'msdevlab', 'Diamonds Are Forever has glamour, but its campier humor and looser 1970s plot do not match Tomorrow Never Dies'' tighter action around a global media villain.', null);  -- 335336 Tomorrow Never Dies 1997 | 85871 Diamonds Are Forever 1971
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (368418, 203649, 2, 'msdevlab', 'The Man with the Golden Gun has an assassin premise, but its thin villain story and 1970s silliness make it much weaker than The World Is Not Enough''s more emotional Bond plot.', null);  -- 368418 World Is Not Enough, The 1999 | 203649 Man with the Golden Gun, The 1974
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (368418, 192514, 2, 'msdevlab', 'Live and Let Die may have memorable villains, but the voodoo and blaxploitation elements feel too dated beside The World Is Not Enough''s personal betrayal and modern spy stakes.', null);  -- 368418 World Is Not Enough, The 1999 | 192514 Live and Let Die 1973
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (30959, 30965, 2, 'msdevlab', 'Batman Forever keeps Gotham and Batman, but the neon colors, jokey villains, and camp tone are the opposite of the grounded fear-and-training story in Batman Begins.', null);  -- 30959 Batman Begins 2005 | 30965 Batman Forever 1995
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (30959, 30967, 2, 'msdevlab', 'Batman Returns has gothic style, yet its strange circus-villain focus and messier plot do not give the clean origin arc and realism that Batman Begins offers.', null);  -- 30959 Batman Begins 2005 | 30967 Batman Returns 1992
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (30959, 30955, 2, 'msdevlab', 'Batman 1989 is iconic, but its more theatrical tone and uneven character depth make it a weak recommendation after Batman Begins'' serious psychological origin story.', null);  -- 30959 Batman Begins 2005 | 30955 Batman 1989
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (30959, 381392, 2, 'msdevlab', 'Batman Beyond reimagines the hero in a futuristic animated teen format, which feels too light and small compared with the cinematic realism of Batman Begins.', null);  -- 30959 Batman Begins 2005 | 381392 "Batman Beyond" 1999
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (30959, 30976, 2, 'msdevlab', 'Mask of the Phantasm has an emotional Batman mystery, but its animated scale makes it feel less satisfying for someone wanting Batman Begins'' full live-action intensity.', null);  -- 30959 Batman Begins 2005 | 30976 Batman: Mask of the Phantasm 1993
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (313477, 313475, 2, 'msdevlab', 'The Phantom Menace is connected to Revenge of the Sith, but its Jar Jar humor, child-centered adventure, and flat politics weaken the dark emotional payoff expected from Episode III.', null);  -- 313477 Star Wars: Episode III - Revenge of the Sith 2005 | 313475 Star Wars: Episode I - The Phantom Menace (1999/II) 1999
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (313477, 313476, 2, 'msdevlab', 'Attack of the Clones sits in the same prequel storyline, yet its stiff romance and slower middle chapter cannot match Revenge of the Sith''s tragedy and momentum.', null);  -- 313477 Star Wars: Episode III - Revenge of the Sith 2005 | 313476 Star Wars: Episode II - Attack of the Clones 2002
