insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (313478, 313476, 2, 'msdevlab', 'Attack of the Clones has Jedi battles and galactic politics, but its awkward dialogue and romance make it a poor substitute for Empire''s tight emotional drama.', null);  -- 313478 Star Wars: Episode V - The Empire Strikes Back 1980 | 313476 Star Wars: Episode II - Attack of the Clones 2002
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (313479, 313474, 2, 'msdevlab', 'The Phantom Menace reaches a heroic ending, yet its kid-focused tone and comic relief do not match the stronger emotional closure of Return of the Jedi.', null);  -- 313479 Star Wars: Episode VI - Return of the Jedi 1983 | 313474 Star Wars: Episode I - The Phantom Menace 1999
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (313477, 313506, 2, 'msdevlab', 'X-Wing includes the same Star Wars universe, but its mission-based flight gameplay misses the character tragedy and dramatic story that make Revenge of the Sith powerful.', null);  -- 313477 Star Wars: Episode III - Revenge of the Sith 2005 | 313506 Star Wars: X-Wing 1995
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (313478, 313464, 2, 'msdevlab', 'Rogue Leader uses Rebel-pilot action, but it is mainly an arcade flight experience, not the character-driven tension that defines The Empire Strikes Back.', null);  -- 313478 Star Wars: Episode V - The Empire Strikes Back 1980 | 313464 Star Wars Rogue Leader: Rogue Squadron 2 2001
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (313477, 313488, 2, 'msdevlab', 'Jedi Starfighter shares space battles with the prequel era, but its vehicle-combat focus lacks the Anakin downfall and emotional stakes of Revenge of the Sith.', null);  -- 313477 Star Wars: Episode III - Revenge of the Sith 2005 | 313488 Star Wars: Jedi Starfighter 2002
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (313489, 313486, 2, 'msdevlab', 'Mysteries of the Sith has Force-user gameplay, yet its dated design and thinner story cannot satisfy someone who liked Knights of the Old Republic for its RPG depth.', null);  -- 313489 Star Wars: Knights of the Old Republic 2003 | 313486 Star Wars: Jedi Knight - Mysteries of the Sith 1998
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (313489, 313493, 2, 'msdevlab', 'Racer Revenge is only a Star Wars racing spin-off, so it misses the choices, characters, and long narrative arc that make Knights of the Old Republic interesting.', null);  -- 313489 Star Wars: Knights of the Old Republic 2003 | 313493 Star Wars: Racer Revenge 2002
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (280284, 280305, 2, 'msdevlab', 'Rocky V follows the same boxer, but its street-level drama feels deflated after Rocky IV''s bigger training montage, patriotic showdown, and inspirational energy.', null);  -- 280284 Rocky IV 1985 | 280305 Rocky V 1990
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (280270, 280305, 2, 'msdevlab', 'The original Rocky works because of its underdog heart, while Rocky V shifts into a bleak street conflict that loses the emotional simplicity of the first film.', null);  -- 280270 Rocky 1976 | 280305 Rocky V 1990
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (280282, 280305, 2, 'msdevlab', 'Rocky III has arena excitement and a memorable comeback arc, but Rocky V replaces that energy with a weaker street story and less satisfying rivalry.', null);  -- 280282 Rocky III 1982 | 280305 Rocky V 1990
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (271095, 159167, 2, 'msdevlab', 'Indiana Jones 4 keeps the adventure brand, but the CGI-heavy alien direction feels forced compared with Raiders of the Lost Ark''s practical danger and clean treasure-hunt momentum.', null);  -- 271095 Raiders of the Lost Ark 1981 | 159167 Indiana Jones 4 2006
