insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (159172, 159175, 2, 'msdevlab', 'Temple of Doom is still Indy, but its harsher violence and darker atmosphere make it a poor fit for fans of Last Crusade''s lighter humor and family dynamic.', null);  -- 159172 Indiana Jones and the Last Crusade 1989 | 159175 Indiana Jones and the Temple of Doom 1984
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (215876, 215878, 2, 'msdevlab', 'Operation Surma uses the IMF name, but its routine gadget missions do not recreate the paranoia, betrayal, and suspense that make the 1996 Mission Impossible memorable.', null);  -- 215876 Mission: Impossible 1996 | 215878 Mission: Impossible - Operation Surma 2003
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (215880, 215877, 2, 'msdevlab', 'The 1998 Mission Impossible entry feels much thinner as a story, especially compared with Mission Impossible III''s personal danger around Ethan and Julia.', null);  -- 215880 Mission: Impossible III 2006 | 215877 Mission: Impossible 1998
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (215880, 215878, 2, 'msdevlab', 'Operation Surma has spy assignments, but it lacks the urgent villain, emotional stakes, and cinematic tension that make Mission Impossible III work.', null);  -- 215880 Mission: Impossible III 2006 | 215878 Mission: Impossible - Operation Surma 2003
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (300229, 311607, 2, 'msdevlab', 'SuperSponge is too game-like and child-focused for a Shrek fan, because Shrek combines fairy-tale satire, adult jokes, and a real emotional arc.', null);  -- 300229 Shrek 2001 | 311607 SpongeBob SquarePants: SuperSponge 2001
