insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (300229, 311604, 2, 'msdevlab', 'SpongeBob''s Lost Spatula is silly in a much more juvenile way, so it does not match Shrek''s mix of parody, romance, and character growth.', null);  -- 300229 Shrek 2001 | 311604 SpongeBob SquarePants: Legend of the Lost Spatula 2001
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (190869, 311606, 2, 'msdevlab', 'Revenge of the Flying Dutchman has goofy cartoon chaos, but it lacks the family theme and emotional loneliness that give Lilo and Stitch its heart.', null);  -- 190869 Lilo & Stitch 2002 | 311606 SpongeBob SquarePants: Revenge of the Flying Dutchman 2002
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (300229, 849, 2, 'msdevlab', 'Patch''s London Adventure is aimed much younger and feels plot-light, which makes it a weak match for Shrek''s layered humor and outsider love story.', null);  -- 300229 Shrek 2001 | 849 101 Dalmatians II: Patch's London Adventure 2003
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (300230, 850, 2, 'msdevlab', 'The 101 Dalmatians sing-along is basically music-focused children''s material, not a full comic story like Shrek 2 with jokes, conflict, and character payoff.', null);  -- 300230 Shrek 2 2004 | 850 101 Dalmatians Sing Along 1996
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (190869, 849, 2, 'msdevlab', 'Patch''s London Adventure has cute animals, but it does not reach Lilo and Stitch''s emotional focus on family, loneliness, and belonging.', null);  -- 190869 Lilo & Stitch 2002 | 849 101 Dalmatians II: Patch's London Adventure 2003
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (300229, 312152, 2, 'msdevlab', 'Spy Kids 3-D is family entertainment, but its video-game gimmick and thin plot do not offer the clever fairy-tale satire that makes Shrek memorable.', null);  -- 300229 Shrek 2001 | 312152 Spy Kids 3-D: Game Over 2003
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (312150, 312152, 2, 'msdevlab', 'The first Spy Kids has a fun family-spy idea, while Spy Kids 3-D turns the series into a much weaker game-world gimmick with less character charm.', null);  -- 312150 Spy Kids 2001 | 312152 Spy Kids 3-D: Game Over 2003
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (312151, 312152, 2, 'msdevlab', 'Spy Kids 2 already leans childish, and Spy Kids 3-D pushes even further into shallow visual gimmicks instead of improving the family-adventure story.', null);  -- 312151 Spy Kids 2: Island of Lost Dreams 2002 | 312152 Spy Kids 3-D: Game Over 2003
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (162380, 312150, 2, 'msdevlab', 'Spy Kids has tech and missions, but its very young target audience makes it a poor match for Iron Man''s confident adult humor, charisma, and superhero stakes.', null);  -- 162380 Iron Man 2005 | 312150 Spy Kids 2001
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (109421, 54209, 2, 'msdevlab', 'Cape Fear turns pursuit into psychological horror and stalking, which is completely different from The Fast and the Furious'' racing, friendship, and adrenaline.', null);  -- 109421 Fast and the Furious, The 2001 | 54209 Cape Fear 1991
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (109421, 120506, 2, 'msdevlab', 'From Hell is a grim Jack the Ripper thriller, so its horror mood does not match the street-racing excitement and lighter energy of The Fast and the Furious.', null);  -- 109421 Fast and the Furious, The 2001 | 120506 From Hell 2001
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (162380, 176711, 2, 'msdevlab', 'Kill Bill is stylish action, but its revenge violence and harsh tone are far darker than Iron Man''s witty, polished superhero adventure.', null);  -- 162380 Iron Man 2005 | 176711 Kill Bill: Vol. 1 2003
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (238072, 276217, 2, 'msdevlab', 'Reservoir Dogs is also about criminals, yet its brutal mistrust and warehouse tension clash with Ocean''s Eleven''s playful, elegant heist style.', null);  -- 238072 Ocean's Eleven 2001 | 276217 Reservoir Dogs 1992
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (238072, 267038, 2, 'msdevlab', 'Pulp Fiction has sharp crime dialogue, but its disturbing violence and cynical structure make it a bad fit for someone expecting Ocean''s Eleven''s charming team heist.', null);  -- 238072 Ocean's Eleven 2001 | 267038 Pulp Fiction 1994
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (129185, 270971, 2, 'msdevlab', 'Raging Bull centers on physical conflict, but its self-destructive psychological portrait is the opposite of Gladiator''s honorable heroism and epic revenge quest.', null);  -- 129185 Gladiator 2000 | 270971 Raging Bull 1980
insert into movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (280284, 270971, 2, 'msdevlab', 'Raging Bull is serious boxing cinema, yet its bleak character study does not match Rocky IV''s uplifting training, music, and Cold War victory feeling.', null);  -- 280284 Rocky IV 1985 | 270971 Raging Bull 1980
